import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import javax.sql.DataSource;

public void processTransaction(DataSource dataSource, int accountId, double transactionAmount) {
    Connection connection = null;
    try {
        connection = dataSource.getConnection();
        connection.setAutoCommit(false);

        String balanceQuery = "SELECT balance FROM accounts WHERE account_id = ?";
        PreparedStatement balanceStatement = connection.prepareStatement(balanceQuery);
        balanceStatement.setInt(1, accountId);
        ResultSet resultSet = balanceStatement.executeQuery();

        if(resultSet.next()) {
            double currentBalance = resultSet.getDouble("balance");
            if(currentBalance >= transactionAmount) {
                String updateQuery = "UPDATE accounts SET balance = balance - ? WHERE account_id = ?";
                PreparedStatement updateStatement = connection.prepareStatement(updateQuery);
                updateStatement.setDouble(1, transactionAmount);
                updateStatement.setInt(2, accountId);
                updateStatement.executeUpdate();
                connection.commit();
            } else {
                System.out.println("Insufficient balance for transaction.");
            }
        } else {
            System.out.println("Account not found.");
        }

    } catch (SQLException e) {
        if (connection != null) {
            try {
                connection.rollback();
            } catch (SQLException ex) {
                ex.printStackTrace();
            }
        }
        e.printStackTrace();
    } finally {
        if (connection != null) {
            try {
                connection.setAutoCommit(true);
                connection.close();
            } catch (SQLException e) {
                e.printStackTrace();
            }
        }
    }
}